package com.granpa.pumpselector;
import android.app.*; import android.graphics.Typeface; import android.view.*; import android.widget.*; import java.util.*;
public class PumpListAdapter extends BaseAdapter{ Activity a; ArrayList<PumpSelector.Result> items=new ArrayList<>(); public PumpListAdapter(Activity a){this.a=a;} public void setItems(List<PumpSelector.Result> l){items.clear(); if(l!=null)items.addAll(l); notifyDataSetChanged();} public PumpSelector.Result getResult(int p){return items.get(p);} public int getCount(){return items.size();} public Object getItem(int p){return items.get(p);} public long getItemId(int p){return p;} public View getView(int p,View v,ViewGroup parent){PumpSelector.Result it=items.get(p); PumpRecord r=it.r; LinearLayout c=Ui.card(a); c.setPadding(Ui.dp(a,14),Ui.dp(a,14),Ui.dp(a,14),Ui.dp(a,14)); c.addView(Ui.text(a,r.model,18,Ui.BLUE,Typeface.BOLD)); c.addView(Ui.text(a,PumpSelector.trim(r.hp)+" HP • "+PumpSelector.trim(r.kw)+" kW • "+r.phase,13,Ui.MUTED,Typeface.BOLD)); c.addView(Ui.text(a,r.category,13,Ui.TEXT,Typeface.NORMAL)); if(it.estimate)c.addView(Ui.text(a,"At "+PumpSelector.head(it.head)+": "+PumpSelector.lph(it.flow)+" • "+it.status,14,Ui.GREEN,Typeface.BOLD)); else c.addView(Ui.text(a,"Head: "+r.headRangeText+" m • Flow: "+r.dischargeRangeText+" "+r.flowUnitOriginal,13,Ui.MUTED,Typeface.NORMAL)); return c;} }
